import android.content.Context
import android.content.SharedPreferences
import kotlin.properties.Delegates

class AuthenticationManager private constructor(context: Context) {
    private val prefs: SharedPreferences = context.getSharedPreferences("auth_prefs", Context.MODE_PRIVATE)
    private var isLoggedIn: Boolean by Delegates.notNull()

    fun getUserID(): String? {
        return prefs.getString("user_id", null)
    }

    fun saveAuthState(token: String, userId: String?) {
        if (userId != null) {
            prefs.edit().putString("token", token).apply()
            prefs.edit().putString("user_id", userId).apply()
            isLoggedIn = true
        }
    }

    fun removeAuthState() {
        prefs.edit().clear().apply()
        isLoggedIn = false
    }

    fun isUserLoggedIn(): Boolean {
        return isLoggedIn
    }

    companion object {
        private var instance: AuthenticationManager? = null

        fun getInstance(context: Context): AuthenticationManager {
            if (instance == null) {
                instance = AuthenticationManager(context)
            }
            return instance!!
        }
    }
}